#include <bits/stdc++.h>
using namespace std;
long long xl(int n){
    if(n==1)return 1;
    long long sum=0;
    for(int i=1;i<=n/2;i++)sum+=xl(i);
    return sum+1;
}
int main(){
    long long n,dp[1001]={0};
    cin>>n;
    dp[1]=1;
    for(int i=2;i<=n;i++){
    	for(int j=1;j<=i/2;j++)dp[i]+=dp[j];
    	dp[i]++;
	}
	cout<<dp[n];
    return 0;
}
